insert into offmarket.business_scores (business_id, score_run_id, layer1_base_rate, layer1_comment, layer2_sellability, layer2_comment, layer3_behavioral_trigger, layer3_comment, layer4_market_pull, layer4_comment, final_score, final_tier, final_comment, value_add_thesis, confidence, data_completeness) values
('c064f4c2-ab1f-5ced-a2ac-80891afc9c81', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 82, 'Dr. Rich earned his DDS from UT School of Dentistry Houston in 1983 with honors (~43 yrs licensed) and is now a senior associate (MAGD) within the Doyle DDS Sugar Land group — strongly implying he is the prior owner who sold to Dr. Doyle in 2019 and is winding down. Tenure proxy ~66-70, deep in the natural-exit window. Note: he''s now an employee/associate, so the ''acquirable'' part of his book may already have transferred; the residual is his remaining personal patient following and the question of when he fully retires. Medium-low confidence.', 60, 'His personal book within the Doyle DDS practice is a recurring-revenue patient following with a clean license and MAGD credentials — but it sits inside someone else''s practice now, so it''s not independently financeable; the ''asset'' is mostly the patient relationships that haven''t yet been absorbed. Caps L2.', 78, 'Strong winding-down profile: a 43-yr veteran who has already sold his practice and is now working as a part-time-ish senior associate — the classic last phase before full retirement. Healthy, clearly disengaged from ownership-growth. Not distress.', 78, 'Fort Bend (Sugar Land) is a top-tier catchment, but the relevant ''transaction'' here largely already happened (sale to Doyle in 2019); residual interest is in the patient-following transfer, not a fresh acquisition. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 75, 'B_forward', 'Dr. Ronald K. Rich, ~67 (license_tenure_proxy), runs Ronald K. Rich, DDS, MAGD (at Doyle DDS, Sugar Land) in Sugar Land, Fort Bend County. Dr. Rich earned his DDS from UT School of Dentistry Houston in 1983 with honors (~43 yrs licensed) and is now a senior associate (MAGD) within the Doyle DDS Sugar Land group — strongly implying he is the prior owner who sold to Dr. Doyle in 2019 and is winding down. Tenure proxy ~66-70, deep in the natural-exit window. Note: he''s now an employee/associate, so the ''acquirable'' part of his book may already have transferred; the residual is his remaining personal patient following and the question of when he fully retires. Medium-low confidence. Strong winding-down profile: a 43-yr veteran who has already sold his practice and is now working as a part-time-ish senior associate — the classic last phase before full retirement. Healthy, clearly disengaged from ownership-growth. Not distress. Fort Bend (Sugar Land) is a top-tier catchment, but the relevant ''transaction'' here largely already happened (sale to Doyle in 2019); residual interest is in the patient-following transfer, not a fresh acquisition. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 75/100. Tier B — hand to the buyer / searcher community.', 'Mostly already-captured — the lever is ensuring his remaining patient following is fully migrated to the buying practice (recall automation, reactivation campaigns). Treat as a ''watch / already-transitioning'' note rather than a target.', 'low', 0.4),
('1781c73e-048e-5621-845c-352c14c61b7b', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 28, 'Dr. Robbins graduated UT School of Dentistry Houston in 2010 (~16 yrs licensed) and her co-dentists also appear mid-career — tenure proxy ~38-44, not near a natural-exit window. Low L1.', 76, 'Clean, well-reviewed (4.9 Google per earlier search) Westchase (77042/77036) general/family/cosmetic practice with 3 providers, ~10 staff, recurring base, modern presence, clean record — a real, financeable, attractive practice; the owners just aren''t sellers.', 26, 'Not coasting — multi-provider, active marketing, high review velocity, mid-career owners. Low L3.', 84, 'Westchase / SW Houston is a solid DSO catchment and a 4.9-star multi-provider practice is a prized bolt-on — but the owners aren''t selling. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 48, 'C_watch', 'Drs. Heather Robbins & Brett McRay (and associates), ~40 (license_tenure_proxy), runs Westchase / Houston Westchase Dentists (Dr. Heather Robbins & associates) in Houston, Harris County. Dr. Robbins graduated UT School of Dentistry Houston in 2010 (~16 yrs licensed) and her co-dentists also appear mid-career — tenure proxy ~38-44, not near a natural-exit window. Low L1. Not coasting — multi-provider, active marketing, high review velocity, mid-career owners. Low L3. Westchase / SW Houston is a solid DSO catchment and a 4.9-star multi-provider practice is a prized bolt-on — but the owners aren''t selling. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 48/100. Tier C — re-score in ~90 days.', 'N/A near-term — owners not winding down. Watch.', 'low', 0.35),
('3847e286-73ca-55bf-a802-5a393800c662', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 36, 'Drs. John and Tina Garza are a husband-and-wife dentist team with 25+ yrs combined experience (so ~12-15 yrs each) and appear mid-career — tenure proxy ~45-52, not at a natural-exit window. Harris County (Cypress, 77433). Low-medium L1.', 74, 'Clean ~18-yr Cypress (77433) family practice, husband-and-wife 2-provider team, ~8 staff, recurring base, clean record — a real, financeable, attractive practice in a high-growth NW Harris suburb; the owners just aren''t sellers.', 32, 'Not coasting — 2 providers, active marketing, mid-career owners in a growth suburb. Low-moderate L3.', 84, 'Cypress / NW Harris (77433) is a high-growth suburb with strong DSO interest; a husband-and-wife 2-provider practice is a clean bolt-on — but the owners aren''t selling. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 52, 'C_watch', 'Drs. John Joseph Garza & Tina Minh Garza, ~50 (license_tenure_proxy), runs Northpointe Family Dentistry (John J. Garza, DDS & Tina M. Garza, DDS) in Cypress, Harris County. Drs. John and Tina Garza are a husband-and-wife dentist team with 25+ yrs combined experience (so ~12-15 yrs each) and appear mid-career — tenure proxy ~45-52, not at a natural-exit window. Harris County (Cypress, 77433). Low-medium L1. Not coasting — 2 providers, active marketing, mid-career owners in a growth suburb. Low-moderate L3. Cypress / NW Harris (77433) is a high-growth suburb with strong DSO interest; a husband-and-wife 2-provider practice is a clean bolt-on — but the owners aren''t selling. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 52/100. Tier C — re-score in ~90 days.', 'N/A near-term — owners not winding down. Watch / re-score in ~5+ yrs.', 'low', 0.35),
('9c5b9621-17c3-506f-944e-77e94601f91b', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 44, 'The practice cites treating the Houston community ''for more than 20 years'' with a multi-dentist team (Drs. Rome, Brooks and others); the principals'' individual ages aren''t verified, so the base rate is moderate/uncertain — whoever is the senior partner may be approaching exit. Low confidence; needs a TSBDE check.', 74, 'A real, ~20-yr NW Houston / Cypress (77065) general/family/cosmetic/sleep-apnea practice with 3 dentists, ~10 staff, recurring base, clean record — financeable and of reasonable size; the unknown is which partner (if any) is the seller.', 40, 'A 3-dentist practice that''s grown over 20+ yrs could be coasting (aging senior partner) or actively run by younger partners — no decline stack verified. Moderate-low L3, low confidence.', 84, 'NW Houston / Cypress (77065) is a high-growth catchment with strong DSO interest; a 3-dentist practice with a 20-yr base is a strong roll-up target. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 56, 'C_watch', 'Drs. Ginger Rome & Maurina Brooks (and team), ~52 (license_tenure_proxy), runs The Dentists at North Cypress (Ginger Rome, DDS & Maurina Brooks, DDS) in Cypress, Harris County. The practice cites treating the Houston community ''for more than 20 years'' with a multi-dentist team (Drs. Rome, Brooks and others); the principals'' individual ages aren''t verified, so the base rate is moderate/uncertain — whoever is the senior partner may be approaching exit. Low confidence; needs a TSBDE check. A 3-dentist practice that''s grown over 20+ yrs could be coasting (aging senior partner) or actively run by younger partners — no decline stack verified. Moderate-low L3, low confidence. NW Houston / Cypress (77065) is a high-growth catchment with strong DSO interest; a 3-dentist practice with a 20-yr base is a strong roll-up target. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 56/100. Tier C — re-score in ~90 days.', 'Pending which partner is the seller: standard recall/AI/scheduling/PMS stack across the practice. Verify partner ages/tenures before acting.', 'low', 0.3)
